<template>
  <view class="page">
    <!-- 地址信息卡片（示意，后续可从用户资料或选择地址获取） -->
    <view class="card address-card">
      <view class="addr-main">
        <text class="addr-title">紫荆校区 · 紫荆公寓5号楼 302</text>
      </view>
      <view class="addr-sub">
        <text class="addr-user">李同学 138****0000</text>
      </view>
    </view>

    <!-- 1. 取件凭证 -->
    <view class="card section-card">
      <text class="section-title">1. 取件凭证（必填）</text>
      <text class="section-desc">请上传取件码截图或短信截图，最多 9 张</text>
      <view class="voucher-box">
        <uni-file-picker
          v-model="vouchers"
          fileMediatype="image"
          :limit="9"
          mode="grid"
        />
      </view>
    </view>

    <!-- 2. 物品规格 -->
    <view class="card section-card">
      <text class="section-title">2. 物品规格</text>
      <view class="spec-row" v-for="item in items" :key="item.key">
        <view class="spec-left">
          <text class="spec-name">{{ item.label }}</text>
          <text class="spec-sub">¥{{ item.price.toFixed(2) }}</text>
        </view>
        <view class="spec-qty">
          <button class="qty-btn" size="mini" @click="changeQty(item.key, -1)">-</button>
          <text class="qty-num">{{ item.qty }}</text>
          <button class="qty-btn" size="mini" @click="changeQty(item.key, 1)">+</button>
        </view>
      </view>
    </view>

    <!-- 3. 增值服务 -->
    <view class="card section-card">
      <text class="section-title">3. 增值服务</text>

      <view class="addon-row">
        <view class="addon-left">
          <text class="addon-name">加急处理</text>
          <text class="addon-sub">+¥1.00</text>
        </view>
        <switch :checked="addons.urgent" @change="onToggle('urgent', $event.detail.value)" />
      </view>

      <view class="addon-row">
        <view class="addon-left">
          <text class="addon-name">送货上门</text>
          <text class="addon-sub">+¥1.00</text>
        </view>
        <switch :checked="addons.door" @change="onToggle('door', $event.detail.value)" />
      </view>
    </view>

    <!-- 底部合计栏 -->
    <view class="bottom-bar">
      <view class="total-box">
        <text class="total-label">合计：</text>
        <text class="total-value">¥ {{ totalPrice.toFixed(2) }}</text>
      </view>
      <button class="pay-btn" type="primary" @click="submitOrder">
        立即支付
      </button>
    </view>
  </view>
</template>

<script>
export default {
  name: 'ExpressPublish',
  data() {
    return {
      vouchers: [],
      items: [
        { key: 'small', label: '小件 (¥1.5)', price: 1.5, qty: 0 },
        { key: 'medium', label: '中件 (¥1.99)', price: 1.99, qty: 0 },
        { key: 'large', label: '大件 (¥2.99)', price: 2.99, qty: 0 }
      ],
      addons: {
        urgent: false,
        door: false
      }
    }
  },
  computed: {
    totalPrice() {
      let sum = 0
      this.items.forEach(i => {
        sum += i.price * i.qty
      })
      if (this.addons.urgent && this.hasAnyItem) sum += 1
      if (this.addons.door && this.hasAnyItem) sum += 1
      return sum
    },
    hasAnyItem() {
      return this.items.some(i => i.qty > 0)
    }
  },
  methods: {
    changeQty(key, delta) {
      this.items = this.items.map(item => {
        if (item.key === key) {
          const next = Math.max(0, item.qty + delta)
          return { ...item, qty: next }
        }
        return item
      })
    },
    onToggle(field, value) {
      this.addons[field] = value
    },
    submitOrder() {
      uni.showToast({
        title: '仅前端示意，暂未接入支付',
        icon: 'none'
      })
    }
  }
}
</script>

<style scoped>
.page {
  min-height: 100vh;
  padding: 16rpx 24rpx 120rpx;
  background: #f5f6f7;
  box-sizing: border-box;
}

.card {
  background: #ffffff;
  border-radius: 16rpx;
  padding: 20rpx 20rpx 24rpx;
  margin-bottom: 16rpx;
  box-shadow: 0 4rpx 14rpx rgba(0, 0, 0, 0.03);
}

.address-card {
  margin-top: 8rpx;
}

.addr-title {
  font-size: 30rpx;
  font-weight: 600;
  color: #333333;
}

.addr-sub {
  margin-top: 6rpx;
}

.addr-user {
  font-size: 26rpx;
  color: #999999;
}

.section-card {
  margin-top: 8rpx;
}

.section-title {
  font-size: 28rpx;
  font-weight: 600;
  color: #333333;
}

.section-desc {
  margin-top: 6rpx;
  font-size: 24rpx;
  color: #999999;
}

.voucher-box {
  margin-top: 16rpx;
}

.spec-row {
  margin-top: 20rpx;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.spec-left {
  flex-direction: column;
}

.spec-name {
  font-size: 28rpx;
  color: #333333;
}

.spec-sub {
  margin-top: 4rpx;
  font-size: 24rpx;
  color: #999999;
}

.spec-qty {
  flex-direction: row;
  align-items: center;
}

.qty-btn {
  width: 56rpx;
  height: 56rpx;
  line-height: 56rpx;
}

.qty-num {
  margin: 0 24rpx;
  min-width: 40rpx;
  text-align: center;
  font-size: 30rpx;
}

.addon-row {
  margin-top: 20rpx;
  flex-direction: row;
  align-items: center;
  justify-content: space-between;
}

.addon-left {
  flex-direction: column;
}

.addon-name {
  font-size: 28rpx;
  color: #333333;
}

.addon-sub {
  margin-top: 4rpx;
  font-size: 24rpx;
  color: #999999;
}

.bottom-bar {
  position: fixed;
  left: 0;
  right: 0;
  bottom: 0;
  padding: 12rpx 24rpx 24rpx;
  background: #ffffff;
  box-shadow: 0 -4rpx 12rpx rgba(0, 0, 0, 0.05);
  flex-direction: row;
  align-items: center;
  justify-content: space-between;
  box-sizing: border-box;
}

.total-box {
  flex-direction: row;
  align-items: baseline;
}

.total-label {
  font-size: 26rpx;
  color: #666666;
}

.total-value {
  margin-left: 6rpx;
  font-size: 32rpx;
  font-weight: 600;
  color: #ff3b30;
}

.pay-btn {
  width: 260rpx;
  border-radius: 999rpx;
  background-color: #007aff;
  color: #ffffff;
}
</style>


